function imgOut = fTrexTonyBgV01(img,bg)%% process background subtraction with Tony's way%% imgOut = fTrexTonyBgV01(img,bg)% img: image% bg: background image% imgOut: subtracted image%% Written by Kei Nakamura% Created on Friday, June 8th 2007.% Modified on%% main bodysumB = sum(sum(bg));sumS = sum(sum(img));if sumB>sumS    imgOut = img - img;    vlH = (sumB-sumS)/numel(img);    %disp(['high back:',num2str(vlH)]);else    imgA = img - bg;                % first process    aN = imgA<0;                    % logic matrix for negative    aP = imgA>0;                    % logic matrix for positive    ngtCnt = -sum(sum(imgA.*aN));    % total counts for negative    imgA = imgA.*aP;                % throw away negative pixels    kk = 1;                         % iteration -> later should be input    while ngtCnt>1&kk<100;                nmbP = sum(sum(aP));        % number of the pixels with positive value        bgA = aP.*(ngtCnt/nmbP);    % new backgrounud image        imgA = imgA - bgA;          % process        aN = imgA<0;                % new logic matrix        aP = imgA>0;        ngtCnt = -sum(sum(imgA.*aN));        imgA = imgA.*aP;                % throw away negative pixels        kk = kk + 1;    end    if kk == 100;        imgA = img - img;        %disp('high back2');    end    imgOut = imgA;end
